#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        long long total = (long long)N * (N + 1) / 2;
        long long sum = 0;
        for (int i = 0; i < N; i++) {
            int Ci;
            scanf("%d", &Ci);
            sum += Ci;
        }
        if (sum != total) {
            printf("NO\n");
            continue;
        }
        long long stamps = 0;
        for (int i = 1; i <= N; i++) {
            int Ci;
            scanf("%d", &Ci);
            stamps += Ci;
            if (stamps < i) {
                printf("NO\n");
                break;
            }
            if (i == N) {
                printf("YES\n");
            }
        }
    }
    return 0;
}

