        while (T-- > 0) {
            int N = sc.nextInt();
            long total = (long)N * (N + 1) / 2;
            long sum = 0;
            for (int i = 0; i < N; i++) {
                int Ci = sc.nextInt();
                sum += Ci;
            }
            if (sum != total) {
                System.out.println("NO");
                continue;
            }
            long stamps = 0;
            for (int i = 1; i <= N; i++) {
                int Ci = sc.nextInt();
                stamps += Ci;
                if (stamps < i) {
                    System.out.println("NO");
                    break;
                }
                if (i == N) {
                    System.out.println("YES");
                }
            }
