const lines = require('fs').readFileSync(0, 'utf-8').trim().split('\n');
let i = 0;
const input = () => lines[i++];
const T = parseInt(input());
for (let t = 0; t < T; t++) {
    const N = parseInt(input());
    const total = N * (N + 1) / 2;
    const Ci = input().split(' ').map(Number);
    const sum = Ci.reduce((a, b) => a + b, 0);
    if (sum !== total) {
        console.log('NO');
        continue;
    }
    let stamps = 0;
    for (let i = 1; i <= N; i++) {
        stamps += Ci[i - 1];
        if (stamps < i) {
            console.log('NO');
            break;
        }
        if (i === N) {
            console.log('YES');
        }
    }
}
